select p.id, p.supplier_id, s.supplier_name, p.cost_plan_id, cp.item_name as cost_plan_name, p.item_name, p.quantity, p.unit_price, p.total_amount, p.status, p.expected_delivery_date, p.actual_delivery_date, p.created_at, p.updated_at from procurement_item p left join supplier_info s on s.id = p.supplier_id and s.is_deleted = 0 left join cost_plan cp on cp.id = p.cost_plan_id and cp.is_deleted = 0 where p.project_id = #{projectId} and p.is_deleted = 0
and p.status = #{query.status}
and p.supplier_id = #{query.supplierId}
and p.cost_plan_id = #{query.costPlanId}
order by p.updated_at desc, p.created_at desc

